const now = new Date();
return [{
  json: {
    typRaportu: 'polowkowy',
    tytul: '☀️ Czas na Raport Połówkowy!',
    deadline: '13:30',
    webhookUrl: 'https://TWOJ-N8N.app/webhook/raport-polowkowy',
    listId: '901522609104',
    statusFiltr: ['ETAP 1-2', 'ETAP 3-4'],
    sprawdzPole: 'Raport Połówkowy Oddany',
    dataStr: now.toLocaleDateString('pl-PL'),
    timeStr: '13:00',
    zarzadEmail: 'autoleads@gmail.com',
    mgrEmail: 'testautoleads@gmail.com',
    sysEmail: 'testautoleads@gmail.com',
    now: now.toISOString()
  }
}];

const now = new Date();
return [{
  json: {
    typRaportu: 'koncowy',
    tytul: '🌆 Czas na Raport Końcowy!',
    deadline: '17:00',
    webhookUrl: 'https://TWOJ-N8N.app/webhook/raport-koncowy',
    listId: '901522609104',
    statusFiltr: ['ETAP 1-2', 'ETAP 3-4', 'ETAP 5'],
    sprawdzPole: 'Raport Końcowy Oddany',
    dataStr: now.toLocaleDateString('pl-PL'),
    timeStr: '16:30',
    zarzadEmail: 'autoleads@gmail.com',
    mgrEmail: 'testautoleads@gmail.com',
    sysEmail: 'testautoleads@gmail.com',
    now: now.toISOString()
  }
}];

const cfg = $input.first().json;

// Sprawdź czy to dane z ClickUp czy config
// Jeśli tasks istnieje to są to dane z ClickUp
const tasks = cfg.tasks || [];

// Pobierz config z poprzedniego noda
const setupData = $('SETUP - Raport Połówkowy').item?.json || 
                   {};

const bezRaportu = [];

tasks.forEach(task => {
  const cf = {};
  (task.custom_fields || []).forEach(f => {
    cf[f.name] = f.value;
  });

  const imie = task.name.split(' | ')[0];
  const email = cf['Email Pracownika'] || setupData.mgrEmail;
  const gPrzyjscia = cf['Godzina Przyjścia'] || cf['Godzina Przyjscia'];

  // Sprawdź czy raport oddany
  const rapOddany = setupData.typRaportu === 'polowkowy'
    ? (cf['Raport Połówkowy Oddany'] === true || cf['Raport Polowkowy Oddany'] === true)
    : (cf['Raport Końcowy Oddany'] === true || cf['Raport Koncowy Oddany'] === true);

  if (gPrzyjscia && !rapOddany) {
    bezRaportu.push({
      taskId: task.id,
      taskUrl: task.url,
      imie,
      email,
      gPrzyjscia
    });
  }
});

return bezRaportu.map(p => ({
  json: {
    ...setupData,
    ...p,
    lacznie: bezRaportu.length
  }
}));

const now = new Date();
return [{
  json: {
    listId: '901522609104',
    listRaportyCodzienne: '901522609089',
    token: 'pk_284536279_ARCLCZPXOG0PMONQ5IBNKY5UJDI4HJRE',
    zarzadEmail: 'autoleads@gmail.com',
    mgrEmail: 'testautoleads@gmail.com',
    sysEmail: 'testautoleads@gmail.com',
    dataStr: now.toLocaleDateString('pl-PL'),
    dataNazwa: now.toLocaleDateString('pl-PL', {
      weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
    }),
    now: now.toISOString()
  }
}];

const cfg = $('SETUP - Konfiguracja Raportu').item.json;
const tasks = $input.first().json.tasks || [];

const pracownicy = tasks.map(task => {
  const cf = {};
  (task.custom_fields || []).forEach(f => { cf[f.name] = f.value; });

  const sp = parseInt(cf['Stan Początkowy'] || cf['Stan Poczatkowy'] || '0');
  const sk = parseInt(cf['Stan Końcowy'] || cf['Stan Koncowy'] || cf['eb918b95-6861-4fe9-bdcf-d325b866042a'] || '0');
  const s13 = parseInt(cf['Stan o 13:00'] || '0');
  const rozdano = sk > 0 ? sp - sk : (s13 > 0 ? sp - s13 : 0);
  const spoznMin = parseInt(cf['Spóźnienie (minuty)'] || cf['Spoznienie'] || '0');

  return {
    imie: task.name.split(' | ')[0],
    status: task.status?.status || '—',
    przybycie: cf['Godzina Przyjścia'] || cf['Godzina Przyjscia'] || '❌',
    wyjscie: cf['Godzina Wyjścia'] || cf['Godzina Wyjscia'] || '—',
    zarej: cf['Czy Zarejestrowana'] === true ? '✅' : '❌',
    sp, s13: s13 || '—', sk: sk || '—',
    rozdano,
    spoznMin,
    rapPol: (cf['Raport Połówkowy Oddany'] || cf['Raport Polowkowy Oddany']) ? '✅' : '❌',
    rapKon: (cf['Raport Końcowy Oddany'] || cf['Raport Koncowy Oddany']) ? '✅' : '❌',
    rapKonTresc: cf['Raport Końcowy'] || cf['Raport Koncowy'] || '',
    rapPolTresc: cf['Raport Połówkowy'] || cf['Raport Polowkowy'] || '',
    flaga: cf['Flaga Problemu'] || 'Brak problemów',
    taskUrl: task.url
  };
});

const stats = {
  lacznie: pracownicy.length,
  obecni: pracownicy.filter(p => p.przybycie !== '❌').length,
  nieobecni: pracownicy.filter(p => p.przybycie === '❌').length,
  spoznieni: pracownicy.filter(p => p.spoznMin > 0).length,
  rozdanoSum: pracownicy.reduce((s, p) => s + p.rozdano, 0),
  rapPolOdd: pracownicy.filter(p => p.rapPol === '✅').length,
  rapKonOdd: pracownicy.filter(p => p.rapKon === '✅').length,
  zakonczone: pracownicy.filter(p => p.status === 'ZAKOŃCZONA').length,
  srednia: pracownicy.length > 0
    ? Math.round(pracownicy.reduce((s, p) => s + p.rozdano, 0) / Math.max(pracownicy.filter(p => p.przybycie !== '❌').length, 1))
    : 0
};

const problemy = {
  bezRapKon: pracownicy.filter(p => p.rapKon === '❌' && p.przybycie !== '❌'),
  nieobecni: pracownicy.filter(p => p.przybycie === '❌'),
  spoznieni: pracownicy.filter(p => p.spoznMin > 0)
};

return [{
  json: {
    ...cfg,
    pracownicy,
    stats,
    problemy,
    maProblemy: problemy.bezRapKon.length > 0 || problemy.nieobecni.length > 0
  }
}];

const d = $input.first().json;
const { pracownicy, stats, problemy } = d;

const wiersze = pracownicy.map((p, i) => {
  const bg = i % 2 === 0 ? '#f8f9fa' : 'white';
  const flagaKolor = p.flaga === 'Brak problemów' ? 'green' :
                     p.flaga.includes('Spóź') ? 'orange' : 'red';
  return `<tr style="background:${bg};">
    <td style="padding:7px 10px;border:1px solid #dee2e6;font-weight:500;">${p.imie}</td>
    <td style="padding:7px;border:1px solid #dee2e6;text-align:center;">${p.przybycie}</td>
    <td style="padding:7px;border:1px solid #dee2e6;text-align:center;">${p.wyjscie}</td>
    <td style="padding:7px;border:1px solid #dee2e6;text-align:center;">${p.zarej}</td>
    <td style="padding:7px;border:1px solid #dee2e6;text-align:center;">${p.sp}</td>
    <td style="padding:7px;border:1px solid #dee2e6;text-align:center;">${p.s13}</td>
    <td style="padding:7px;border:1px solid #dee2e6;text-align:center;font-weight:bold;color:#667eea;">${p.rozdano}</td>
    <td style="padding:7px;border:1px solid #dee2e6;text-align:center;">${p.rapPol}</td>
    <td style="padding:7px;border:1px solid #dee2e6;text-align:center;">${p.rapKon}</td>
    <td style="padding:7px;border:1px solid #dee2e6;text-align:center;color:${flagaKolor};font-size:11px;font-weight:bold;">${p.flaga}</td>
  </tr>`;
}).join('');

const problHTML = d.maProblemy ? `
<div style="background:#fff3cd;border:1px solid #ffc107;border-radius:8px;padding:15px;margin:15px 0;">
  <h3 style="color:#856404;margin:0 0 10px;">⚠️ Problemy Dnia</h3>
  ${problemy.bezRapKon.length > 0 ? `<p><b>Brak raportu końcowego:</b> ${problemy.bezRapKon.map(p => p.imie).join(', ')}</p>` : ''}
  ${problemy.nieobecni.length > 0 ? `<p><b>Nieobecne bez zgłoszenia:</b> ${problemy.nieobecni.map(p => p.imie).join(', ')}</p>` : ''}
  ${problemy.spoznieni.length > 0 ? `<p><b>Spóźnienia:</b> ${problemy.spoznieni.map(p => p.imie + ' (' + p.spoznMin + ' min)').join(', ')}</p>` : ''}
</div>` : '<div style="background:#d4edda;border-radius:8px;padding:12px;margin:15px 0;"><p style="color:#155724;margin:0;">✅ Brak problemów - świetny dzień!</p></div>';

const raportyHTML = pracownicy.filter(p => p.rapKonTresc || p.rapPolTresc)
  .map(p => `
  <div style="background:#f8f9fa;padding:12px;border-radius:6px;margin:8px 0;border-left:3px solid #667eea;">
    <b>${p.imie}</b> <span style="color:${p.flaga === 'Brak problemów' ? 'green' : 'red'};font-size:12px;">● ${p.flaga}</span>
    ${p.rapPolTresc ? `<p style="margin:6px 0;font-size:13px;"><em>13:00:</em> ${p.rapPolTresc}</p>` : ''}
    ${p.rapKonTresc ? `<p style="margin:6px 0;font-size:13px;"><em>Końcowy:</em> ${p.rapKonTresc}</p>` : ''}
  </div>`).join('');

const html = `<!DOCTYPE html>
<html>
<body style="font-family:Arial,sans-serif;max-width:950px;margin:0 auto;">
<div style="background:linear-gradient(135deg,#667eea,#764ba2);color:white;padding:28px;border-radius:12px 12px 0 0;">
  <h1 style="margin:0;font-size:26px;">📊 Raport Końcowy Dnia - Hostessy</h1>
  <p style="opacity:0.9;margin:6px 0 0;font-size:15px;">Data: <b>${d.dataNazwa}</b></p>
</div>
<div style="background:white;padding:25px;border:1px solid #eee;">
  <h2 style="color:#444;border-bottom:2px solid #667eea;padding-bottom:8px;">📈 Podsumowanie</h2>
  <div style="display:flex;gap:12px;flex-wrap:wrap;margin:15px 0;">
    <div style="background:#e8f5e9;padding:15px;border-radius:8px;text-align:center;flex:1;min-width:80px;"><div style="font-size:26px;font-weight:bold;color:#2e7d32;">${stats.obecni}</div><small>Obecnych</small></div>
    <div style="background:#fce4ec;padding:15px;border-radius:8px;text-align:center;flex:1;min-width:80px;"><div style="font-size:26px;font-weight:bold;color:#c62828;">${stats.nieobecni}</div><small>Nieobecnych</small></div>
    <div style="background:#e3f2fd;padding:15px;border-radius:8px;text-align:center;flex:1;min-width:80px;"><div style="font-size:26px;font-weight:bold;color:#1565c0;">${stats.rozdanoSum}</div><small>Rozdano łącznie</small></div>
    <div style="background:#fff8e1;padding:15px;border-radius:8px;text-align:center;flex:1;min-width:80px;"><div style="font-size:26px;font-weight:bold;color:#e65100;">${stats.srednia}</div><small>Średnia/osoba</small></div>
    <div style="background:#f3e5f5;padding:15px;border-radius:8px;text-align:center;flex:1;min-width:80px;"><div style="font-size:26px;font-weight:bold;color:#6a1b9a;">${stats.rapKonOdd}/${stats.lacznie}</div><small>Raporty końcowe</small></div>
    <div style="background:#e0f2f1;padding:15px;border-radius:8px;text-align:center;flex:1;min-width:80px;"><div style="font-size:26px;font-weight:bold;color:#00695c;">${stats.spoznieni}</div><small>Spóźnienia</small></div>
  </div>
  ${problHTML}
  <h2 style="color:#444;border-bottom:2px solid #667eea;padding-bottom:8px;margin-top:20px;">👥 Tabela Pracowników</h2>
  <div style="overflow-x:auto;">
  <table style="width:100%;border-collapse:collapse;font-size:12px;">
    <thead><tr style="background:linear-gradient(135deg,#667eea,#764ba2);color:white;">
      <th style="padding:10px;text-align:left;">Imię</th>
      <th style="padding:10px;">Przybycie</th>
      <th style="padding:10px;">Wyjście</th>
      <th style="padding:10px;">Rejestr.</th>
      <th style="padding:10px;">Stan P.</th>
      <th style="padding:10px;">13:00</th>
      <th style="padding:10px;">Rozdano</th>
      <th style="padding:10px;">Rap.Poł.</th>
      <th style="padding:10px;">Rap.Końc.</th>
      <th style="padding:10px;">Status</th>
    </tr></thead>
    <tbody>${wiersze}</tbody>
  </table>
  </div>
  ${raportyHTML ? `<h2 style="color:#444;border-bottom:2px solid #667eea;padding-bottom:8px;margin-top:20px;">📝 Raporty Pracowników</h2>${raportyHTML}` : ''}
</div>
<div style="background:#f8f9fa;padding:12px;text-align:center;border:1px solid #eee;border-radius:0 0 12px 12px;">
  <small style="color:#888;">Automatyczny raport dzienny | ${new Date().toLocaleString('pl-PL')}</small>
</div>
</body>
</html>`;

return [{
  json: {
    ...d,
    html,
    subject: `📊 Raport Końcowy Hostessy - ${d.dataStr} | ${d.maProblemy ? '⚠️ PROBLEMY' : '✅ OK'} | Rozdano: ${stats.rozdanoSum} szt.`
  }
}];

const now = new Date();
const nowMin = now.getHours() * 60 + now.getMinutes();
const startMin = 8 * 60;
const minPoStart = nowMin - startMin;

return [{
  json: {
    listId: '901522609104',
    listRaporty: '901522609109',
    listAlerty: '901522609082',
    token: 'pk_284536279_ARCLCZPXOG0PMONQ5IBNKY5UJDI4HJRE',
    nowMin,
    minPoStart,
    startMin,
    rapPolMin: 13 * 60,
    rapKonMin: 17 * 60,
    progNiskiStan: 30,
    progSpoznMin: 15,
    progSpoznZarzad: 3,
    zarzadEmail: 'autoleady@gmail.com',
    mgrEmail: 'testautoleady@gmail.com',
    sysEmail: 'testautoleady@gmail.com',
    dataStr: now.toLocaleDateString('pl-PL'),
    timeStr: now.toLocaleTimeString('pl-PL', {hour:'2-digit', minute:'2-digit'}),
    now: now.toISOString()
  }
}];

const cfg = $('SETUP - Konfiguracja').item.json;
const { nowMin, startMin, minPoStart, rapPolMin, progNiskiStan, progSpoznMin } = cfg;

let tasks = [];
const firstJson = $input.first().json;

if (firstJson.tasks && Array.isArray(firstJson.tasks)) {
  tasks = firstJson.tasks;
} else if (Array.isArray(firstJson)) {
  tasks = firstJson;
} else {
  tasks = $input.all().map(item => item.json);
}

tasks = tasks.filter(t => t.id && t.custom_fields);

const alerty = [];
const stats = {
  lacznie: tasks.length,
  obecni: 0,
  spoznieni: 0,
  nieobecni: 0,
  bezRapPol: 0,
  niskaIlosc: 0,
  wymagaUwagi: 0
};

// ============================================
// MECHANIZM DEDUPLIKACJI
// Sprawdź kiedy ostatnio wysłano alert dla danego taska+typu
// Używamy custom field "Uwagi Managera" lub date_updated jako proxy
// GŁÓWNA LOGIKA: alert tego samego typu dla tego samego taska
// wysyłamy max raz na X minut
// ============================================
const COOLDOWN_SPOZNIENIE   = 240; // min - spóźnienie: raz na 4h (już wiemy, nie spam)
const COOLDOWN_NIEOBECNOSC  = 60;  // min - nieobecność: co godzinę
const COOLDOWN_BRAK_RAP_POL = 30;  // min - brak raportu pol: co 30 min
const COOLDOWN_NISKI_STAN   = 60;  // min - niski stan: co godzinę

// Klucz: taskId_typ → timestamp ostatniego alertu
// Przechowujemy w custom field "date_updated" taska jako proxy
// LUB sprawdzamy przez pole tekstowe w tasku
// 
// Najprostsze rozwiązanie: sprawdź date_updated taska
// Jeśli task był update'owany niedawno przez system = alert już wysłano

function minutySinceMs(ms) {
  const now = Date.now();
  return Math.floor((now - parseInt(ms)) / 60000);
}

tasks.forEach(task => {
  const cf = {};
  (task.custom_fields || []).forEach(f => {
    if (f.value !== undefined && f.value !== null) {
      cf[f.name] = f.value;
    }
  });

  const imie    = task.name.trim();
  const taskId  = task.id;
  const taskUrl = task.url;
  const email   = cf['Email'] || cfg.mgrEmail;

  const gPrzyjscia  = cf['Godzina Przyjścia'] || cf['Godzina Przyjscia'] || null;
  const stan13      = parseInt(cf['Stan o 13:00']    || '0') || 0;
  const stanPocz    = parseInt(cf['Stan Początkowy'] || cf['Stan Poczatkowy'] || '0') || 0;
  const rapPol      = cf['Raport Połówkowy'] || cf['Raport Polowkowy'] || null;
  const liczbaSpozn = parseInt(cf['Liczba Spóźnień (łącznie)'] || '0') || 0;
  const status      = (task.status?.status || '').toLowerCase();

  // ---- Minuty od ostatniej aktualizacji taska ----
  const minutesSinceUpdate = minutySinceMs(task.date_updated || task.date_created || 0);

  if (status === 'wymaga uwagi') stats.wymagaUwagi++;

  // ---- OBECNOŚĆ I SPÓŹNIENIE ----
  if (gPrzyjscia && gPrzyjscia.trim() !== '') {
    stats.obecni++;

    const parts = gPrzyjscia.split(':');
    if (parts.length === 2) {
      const hP        = parseInt(parts[0]) || 0;
      const mP        = parseInt(parts[1]) || 0;
      const przyjMin  = hP * 60 + mP;
      const spoznMinut = przyjMin - startMin;

      if (spoznMinut > progSpoznMin) {
        stats.spoznieni++;

        // DEDUPLIKACJA SPÓŹNIENIA:
        // Wyślij alert spóźnienia TYLKO jeśli:
        // - to pierwsza rejestracja (liczbaSpozn zmiana) - task był update'owany < 30 min temu
        // - LUB minęło więcej niż COOLDOWN od ostatniego alertu
        // 
        // Heurystyka: jeśli task był zaktualizowany < 20 min temu
        // = właśnie się zarejestrowała = wyślij alert (pierwsze spóźnienie tego dnia)
        // Jeśli update był dawno = już wiemy o tym spóźnieniu = nie wysyłaj ponownie

        const czyNoweSpoznienie = minutesSinceUpdate < 20;
        const czyPoKooldownie   = minutesSinceUpdate > COOLDOWN_SPOZNIENIE;

        if (czyNoweSpoznienie || czyPoKooldownie) {
          alerty.push({
            typ:          'spoznienie',
            ikona:        '⚠️',
            taskId,
            taskUrl,
            imie,
            email,
            info:         `Spóźnienie ${spoznMinut} min (łącznie: ${liczbaSpozn + 1}x)`,
            pilne:        liczbaSpozn >= cfg.progSpoznZarzad,
            spoznMin:     spoznMinut,
            liczbaSpozn,
            czyNowe:      czyNoweSpoznienie
          });
        }
        // else: znamy to spóźnienie, nie spamujemy
      }
    }
  } else if (minPoStart > 30) {
    stats.nieobecni++;

    // DEDUPLIKACJA NIEOBECNOŚCI:
    // Wyślij alert co COOLDOWN_NIEOBECNOSC minut
    // Sprawdź przez minutesSinceUpdate:
    // Pierwsze wykrycie: task nie był update'owany = minutesSinceUpdate duże = wyślij
    // Kolejne: nie aktualizujemy taska przy braku osoby = zawsze duże = PROBLEM
    //
    // Rozwiązanie: użyj nowMin jako "okna"
    // Wysyłaj alert nieobecności tylko co pełną godzinę (np. 9:00, 10:00...)
    // lub przy pierwszym wykryciu (minPoStart == 31-45)

    const czyPierwszeWykrycie = minPoStart >= 30 && minPoStart <= 45;
    const czyCykliczne        = nowMin % 60 < 15; // pierwsze 15 min każdej godziny

    if (czyPierwszeWykrycie || czyCykliczne) {
      alerty.push({
        typ:    'nieobecnosc',
        ikona:  '❌',
        taskId,
        taskUrl,
        imie,
        email,
        info:   `Nieobecna ${minPoStart} min po starcie`,
        pilne:  minPoStart > 60
      });
    }
  }

  // ---- BRAK RAPORTU POŁÓWKOWEGO ----
  const rapPolOddany = cf['Raport Połówkowy Oddany'] === true
    || cf['Raport Połówkowy Oddany'] === 'true'
    || cf['Raport Polowkowy Oddany'] === true
    || !!rapPol;

  if (nowMin > rapPolMin + 30 && !rapPolOddany && gPrzyjscia) {
    stats.bezRapPol++;

    // DEDUPLIKACJA BRAK RAPORTU POŁ:
    // Wysyłaj tylko:
    // - raz zaraz po 13:30 (nowMin w oknie 810-825)
    // - raz po 14:00 (nowMin w oknie 840-855) jeśli dalej brak
    // - raz po 14:30 jako ostatnie przypomnienie

    const okno1 = nowMin >= rapPolMin + 30  && nowMin < rapPolMin + 45;  // 13:30-13:45
    const okno2 = nowMin >= rapPolMin + 60  && nowMin < rapPolMin + 75;  // 14:00-14:15
    const okno3 = nowMin >= rapPolMin + 90  && nowMin < rapPolMin + 105; // 14:30-14:45

    if (okno1 || okno2 || okno3) {
      alerty.push({
        typ:      'brak_raportu_pol',
        ikona:    '📋',
        taskId,
        taskUrl,
        imie,
        email,
        info:     `Brak raportu połówkowego (po ${okno1 ? '13:30' : okno2 ? '14:00' : '14:30'})`,
        pilne:    nowMin > rapPolMin + 60,
        oknoAlertu: okno1 ? 1 : okno2 ? 2 : 3
      });
    }
  }

  // ---- NISKI STAN ----
  const stanAktualny = stan13 > 0 ? stan13 : stanPocz;
  if (stanAktualny > 0 && stanAktualny < progNiskiStan && gPrzyjscia) {
    stats.niskaIlosc++;

    // DEDUPLIKACJA NISKI STAN:
    // Task był update'owany gdy wpisano niski stan
